import{_ as a,o as r,c as e,ag as d}from"./chunks/framework.CAXxHpAX.js";const g=JSON.parse('{"title":"全书目录","description":"","frontmatter":{},"headers":[],"relativePath":"catalog.md","filePath":"catalog.md"}'),s={name:"catalog.md"};function o(h,t,l,i,n,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="全书目录" tabindex="-1">全书目录 <a class="header-anchor" href="#全书目录" aria-label="Permalink to &quot;全书目录&quot;">​</a></h1><h2 id="全书分部" tabindex="-1">全书分部 <a class="header-anchor" href="#全书分部" aria-label="Permalink to &quot;全书分部&quot;">​</a></h2><ul><li><strong>第一部分：PostgreSQL 建立数据库直觉</strong>：让读者先理解数据如何被组织、约束、查询、优化，以及单机数据库为什么会出现边界。</li><li><strong>第二部分：从业务库走向分析系统</strong>：解释 OLTP / OLAP 分工、数仓建模和 ETL / CDC，让读者理解数据平台不是工具堆叠，而是系统目标分化后的结果。</li><li><strong>第三部分：大数据计算与湖仓底座</strong>：把批处理、实时计算和 OLAP 引擎放到同一条链路中，理解历史分析、实时分析和交互分析的不同压力。</li><li><strong>第四部分：AI 时代的数据基础设施</strong>：把向量、图、湖仓和治理纳入统一数据系统，理解 AI 应用为什么依赖可信、可追溯、可检索的数据底座。</li><li><strong>第五部分：项目、路线和能力闭环</strong>：用项目实战、学习顺序、能力地图和最终目标，把全书从知识阅读落到可执行训练。</li></ul><h2 id="章节清单" tabindex="-1">章节清单 <a class="header-anchor" href="#章节清单" aria-label="Permalink to &quot;章节清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>章节</th><th>阅读目标</th></tr></thead><tbody><tr><td><a href="/chapters/00-positioning">0. 核心定位</a></td><td>说明本书为什么以 PostgreSQL 为入口，如何把数据库学习连接到大数据与 AI 数据基础设施。</td></tr><tr><td><a href="/chapters/01-postgresql-foundations">1. 数据库基础：用 PostgreSQL 建立数据系统直觉</a></td><td>用 PostgreSQL 建立数据如何被组织、约束、查询和保持一致的基础直觉。</td></tr><tr><td><a href="/chapters/02-sql-analysis">2. SQL 分析能力：大数据方向第一硬技能</a></td><td>把 SQL 从查询语法提升为分析表达能力，训练取数、聚合、关联、窗口和指标口径。</td></tr><tr><td><a href="/chapters/03-postgresql-large-tables">3. PostgreSQL 大表能力：理解单机数据库边界</a></td><td>从分区、索引、物化视图和执行计划理解 PostgreSQL 如何支撑大表，以及边界在哪里。</td></tr><tr><td><a href="/chapters/04-oltp-olap">4. OLTP vs OLAP：大数据系统的第一分水岭</a></td><td>解释业务交易和分析计算为什么会分化，以及 PostgreSQL 与 OLAP 系统如何分工。</td></tr><tr><td><a href="/chapters/05-data-warehouse-modeling">5. 数据仓库建模：从表设计到分析建模</a></td><td>把业务表重构成事实表、维度表、分层模型和稳定指标体系。</td></tr><tr><td><a href="/chapters/06-etl-elt">6. ETL / ELT：数据如何进入大数据系统</a></td><td>说明 PostgreSQL 数据如何通过批量同步、CDC、转换和调度进入数据平台。</td></tr><tr><td><a href="/chapters/07-batch-processing">7. 批处理系统：Hive / Spark / Trino</a></td><td>理解 Hive、Spark、Trino 在历史数据加工、分布式计算和跨源分析中的定位。</td></tr><tr><td><a href="/chapters/08-stream-processing">8. 实时数据处理：Kafka / Flink</a></td><td>围绕事件流、状态、窗口、水位线和一致性理解实时数据系统。</td></tr><tr><td><a href="/chapters/09-olap-databases">9. OLAP 数据库：ClickHouse / Doris / DuckDB</a></td><td>理解列式存储、MPP、本地 OLAP 和 PostgreSQL 到分析库的链路。</td></tr><tr><td><a href="/chapters/10-vector-databases">10. 向量数据库：面向 AI / RAG / 语义检索的数据系统</a></td><td>把非结构化数据转成可检索语义空间，理解 RAG、混合检索和向量治理。</td></tr><tr><td><a href="/chapters/11-graph-databases">11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统</a></td><td>理解节点、边、路径、多跳查询、知识图谱和 GraphRAG 在数据平台中的位置。</td></tr><tr><td><a href="/chapters/12-lakehouse">12. 数据湖与湖仓架构</a></td><td>用对象存储、文件格式、表格式、Catalog 和多引擎查询构建开放分析底座。</td></tr><tr><td><a href="/chapters/13-data-governance">13. 数据治理与工程化</a></td><td>覆盖质量、元数据、血缘、权限、指标和 AI 知识治理，让数据平台长期可信。</td></tr><tr><td><a href="/chapters/14-projects">14. 大数据方向项目实战</a></td><td>用 7 个项目把 PostgreSQL、OLAP、实时、湖仓、RAG、图和治理串成可执行闭环。</td></tr><tr><td><a href="/chapters/15-learning-order">15. 推荐学习顺序</a></td><td>给出从 PostgreSQL 到数据治理的阶段化学习路径，避免直接跳工具。</td></tr><tr><td><a href="/chapters/16-capability-map">16. 能力地图</a></td><td>把全书能力沉淀为 SQL、建模、链路、选型和治理五类能力。</td></tr><tr><td><a href="/chapters/17-final-goals">17. 最终学习目标</a></td><td>定义从会查数据到会构建智能数据系统的最终能力标准。</td></tr></tbody></table><h2 id="阅读建议" tabindex="-1">阅读建议 <a class="header-anchor" href="#阅读建议" aria-label="Permalink to &quot;阅读建议&quot;">​</a></h2><p>如果你已经会写基础 SQL，但不理解数据平台，可以从第 3 章开始，先补齐大表、执行计划和单机边界，再进入第 4 章 OLTP / OLAP 分化。</p><p>如果你正在做 AI 应用或 RAG，不建议直接跳到向量数据库。至少先读第 5-6 章，理解数据建模、同步、质量和血缘，否则向量检索很容易变成不可治理的临时索引。</p><p>如果你想形成工程作品集，先通读第 14 章项目实战，再回到相关章节补机制。项目不是展示工具安装，而是展示数据从业务库进入分析系统、实时系统、AI 检索和治理系统的完整链路。</p>',9)])])}const f=a(s,[["render",o]]);export{g as __pageData,f as default};
